        uint256 unreleased = totalReceived - totalReleased;
        if (payee == payee1) {
            return (unreleased * share1) / 100 - releasedToPayee1;
        } else if (payee == payee2) {
            return (unreleased * share2) / 100 - releasedToPayee2;
        }
        return 0;
    }

