        if (payee == payee1) {
            releasedToPayee1 += releasable;
        } else if (payee == payee2) {
            releasedToPayee2 += releasable;
        }

        totalReleased += releasable;
        (bool success,) = payee.call{value: releasable}("");
        require(success, "Transfer failed");
        emit Release(payee, releasable);
    }
}
